  ('fed-001', 'NRC Industrial Research Assistance Program (IRAP)', 'National Research Council Canada', 1000000, 74, null, 'hard', 'Federal', array['Canadian SME, fewer than 500 employees, incorporated, conducting technology-driven R&D. Must engage an NRC-IRAP Industrial Technology Advisor (ITA).', '1+ employees'], 20, 'Canada''s flagship SME innovation grant. Funds technology R&D projects via technical and business advisory services plus financial contributions. Rolling intake year-round.', 'https://nrc.canada.ca/en/support-technology-innovation/nrc-irap', 'Rolling - intake open', array['Technology', 'Manufacturing', 'Clean Technology', 'Agriculture', 'Healthcare', 'Aerospace', 'AI & Digital'], array['All Canada'], true, 'Canadian SME, fewer than 500 employees, incorporated, conducting technology-driven R&D. Must engage an NRC-IRAP Industrial Technology Advisor (ITA).', array['Confirm current intake status on the official program page', 'Verify business eligibility against RTM readiness requirements', 'Gather required business and financial documents', 'Prepare project narrative, budget, and expected outcomes', 'Submit through the official portal or proceed with RTM advisor support'], null, 'National Research Council Canada', 'Innovation & R&D', 'Technology R&D', 'Federal', 'ALL', 'grant', 25000, 1000000, 'Up to $1,000,000', '{}'::text[], array['Startup', 'Growth', 'Established'], 0, 1, 500, 0, 50000000, 60, 'rolling', true, false, true, false, 0, array['r_and_d', 'innovation', 'technology', 'advisory', 'wage_subsidy'], true, '[{"key":"business_name","label":"Legal business name","required":true,"weight":2},{"key":"legal_structure","label":"Legal structure (incorporated, sole prop, etc.)","required":true,"weight":1},{"key":"province","label":"Primary province of operation","required":true,"weight":2},{"key":"industry","label":"Industry or sector","required":true,"weight":1},{"key":"employee_count","label":"Number of employees","required":true,"weight":1},{"key":"rev