  ('fed-002', 'SR&ED — Scientific Research & Experimental Development Tax Credit', 'Canada Revenue Agency', 3000000, 74, null, 'hard', 'Federal', array['Any Canadian corporation conducting eligible R&D. CCPCs get enhanced rate. Can be claimed retroactively up to 18 months.', '1+ employees'], 70, 'Canada''s largest R&D incentive. CCPCs receive 35% enhanced refundable ITC on eligible R&D expenditures up to $6M (doubled from $3M in Budget 2025). Larger corps get 15% non-refundable. Claimed on annual T2 return.', 'https://www.canada.ca/en/revenue-agency/services/scientific-research-experimental-development-tax-incentive-program.html', 'Annual - intake open', array['Technology', 'Manufacturing', 'Clean Technology', 'Agriculture', 'Healthcare', 'Aerospace', 'Pharma', 'AI & Digital'], array['All Canada'], true, 'Any Canadian corporation conducting eligible R&D. CCPCs get enhanced rate. Can be claimed retroactively up to 18 months.', array['Confirm current intake status on the official program page', 'Verify business eligibility against RTM readiness requirements', 'Gather required business and financial documents', 'Prepare project narrative, budget, and expected outcomes', 'Submit through the official portal or proceed with RTM advisor support'], null, 'Canada Revenue Agency', 'Tax Credits', 'R&D Tax Credit', 'Federal', 'ALL', 'tax_credit', 10000, 3000000, '35% refundable ITC on first $6M of R&D (CCPCs)', '{}'::text[], array['Startup', 'Growth', 'Established'], 0, 1, 10000, 0, 500000000, 80, 'annual', true, false, true, false, 0, array['tax_credit', 'r_and_d', 'refundable', 'cra', 'annual_filing'], true, '[{"key":"business_name","label":"Legal business name","required":true,"weight":2},{"key":"legal_structure","label":"Legal structure (incorporated, sole prop, etc.)","required":true,"weight":1},{"key":"province","label":"Primary province of operation","required":true,"weight":2},{"key":"industry","label":"Industry or sector","required":true,"weight":1},{"key":"employee_co